--在协议数据处理完之后需要调用finish
function ModelChat:OnModelRequest()
    self:InitData()
    self._timer = LxTimer:New()
    self:ModelFinish()
end
function ModelChat:InitData()
    self._channelListCD = {}                --频道列表冷却cd
    self._channleNmuber = {}                --频道列表信息计数
    local privateMsgs = {}
    if self._chatInfoList then
        privateMsgs = self._chatInfoList[ModelChat.CHANNEL_PRIVATE]
    end
    self._chatInfoList = {}                 --频道聊天信息列表
    self._chatInfoList[ModelChat.CHANNEL_PRIVATE] = privateMsgs
    self._noticeInfoList = {}               --公告列表
    self._channelRedList = {}               --频道红点列表
    self._privateRedList = {}               --私聊红点列表
    self._channelATList = {}                --频道@的列表
    local chatSetServerList = LPlayerPrefs.chatSetServerList
    if string.isempty(chatSetServerList) then
        --local str = ""
        local dataList = {}
        for i, v in pairs(GameTable.ChattingSetRef) do
            local str = string.format("%s=%s", v.type, v.open)
            --if v.open then
            --    if string.isempty(str)then
            --        str = v.type .."=".. v.open
            --    else
            --        str = str .. "|"..v.type .."=".. v.open
            --    end
            --end
            table.insert(dataList, str)
        end
        local str = table.concat(dataList, "|")
        LPlayerPrefs.SetChatSetServerList(str)
    end


    if gLGameLanguage:CheckIsVie119Pack()  then
        GF.OpenUIGue("UISistemNotice",{isVie119 = true })
        self._runTimer = LxTimer.LoopTimeCall(function ()
            GF.OpenUIGue("UISistemNotice",{isVie119 = true })
        end, 60, false)
    end

end
function ModelChat:ParseConfig()
    local _faceBinToFaceRefId = {}
    self._faceBinToFaceRefId = _faceBinToFaceRefId
    for k, v in pairs(GameTable.ChattingFaceRef) do
        if v.faceinstead2 then
            _faceBinToFaceRefId[v.faceinstead2] = v.refId
        end
    end

    local chatChannelRef = {}
    for i, v in pairs(GameTable.ChattingChannelRef) do
        chatChannelRef[v.channelId] = v
    end
    self._chatChannelRef = chatChannelRef
end
function ModelChat:GetFaceBinToFaceRefIdData()
    return self._faceBinToFaceRefId
end
