------------------------------------------------协议操作------------------------------------------------
function ModelChat:OnChatMsgReq(channel, type, msg, playerId, playerName, extraMsg, serverId, isNoRestrictLv)
    --发送消息
    local sensitive = gModelPlayer:GetChatForbid(ModelPlayer.SENSITIVE_TYPE_1)
    if not sensitive then
        GF.ShowMessage(ccClientText(30800))
        return
    end
    if not isNoRestrictLv then
        local bool = self:GetChatChannelIsOpent(channel, 2, true)
        if (not bool) then
            return
        end
    end

    msg = LUtil.ChatInfoFaceDecToBin(msg)
    --local _msg = LWordMaskUtil.ClearShieldWord(msg,false,nil,true)

    local sceneType = nil
    if channel == ModelChat.CHANNEL_PRIVATE then
        sceneType = LGameWordMask.SCENE_TYPE_PRIVATE_CHAT
    elseif channel == ModelChat.CHANNEL_GUILD then
        sceneType = LGameWordMask.SCENE_TYPE_HALF_PUBLIC_CHAT
    else
        sceneType = LGameWordMask.SCENE_TYPE_PUBLIC_CHAT
    end

    local func = function(isMatched, newText)
        if isMatched then
            GF.ShowMessage(ccClientText(11165))
            return
        end

        local pb = LProtoHelper.CreateProto(LProtoIds.ChatMsgReq)
        pb.channel = channel
        pb.type = type
        pb.msg = newText
        if playerId then
            pb.playerId = playerId
        end
        if playerName then
            pb.playerName = playerName
        end
        if extraMsg then
            pb.extraMsg = extraMsg
        end
        if serverId then
            pb.serverId = serverId
        end
        SendMessage(pb, LProtoIds.ChatMsgReq)
        if not isNoRestrictLv then
            self:SetChatChannelCD(channel)
        end
    end

    LWordMaskUtil.ClearShieldWordEx(msg, false, true, sceneType, func)

end
