function ModelChat:OnChatMsgPushResp(pb)
    --信息下发
    local msgs = pb.msgs
    local isSaveChat = false
    local saveChatIdList = {}
    local meId = gModelPlayer:GetPlayerId()
    local timeKey = LPlayerPrefs.chatChannelTime or ""
    local timeKeyArr = string.split(timeKey, "|")
    local chatChannelTime = {}
    for i, v in ipairs(timeKeyArr) do
        local arr = string.split(v, "=")
        chatChannelTime[tonumber(arr[1])] = arr[2]
    end
    local endMsg
    local endTime = nil
    for i, v in ipairs(msgs) do
        local msg = self:SetChatMsg(v)

        if not endTime or endTime < msg.sendTime then
            endTime = msg.sendTime
            endMsg = msg
        end

        --endMsg = msg
        local bChatStatus = false--是否禁言
        if (msg.chatStatus == 1 and msg.playerId ~= meId) then
            bChatStatus = true
        end
        if (not bChatStatus) then
            self:SetChannelInfoByChannel(msg.channel, msg)
            local channelTime = chatChannelTime[msg.channel] or "0"
            if msg.sendTime > channelTime then
                if (not gModelFriend:GetBAddHei(msg.playerId)) then
                    if (msg.type == ModelChat.MSGTYPE_AT) then
                        --3是@人
                        if (msg.atPlayerId == meId) then
                            --当@的人是自己
                            self:SetChannelCallList(msg.channel, msg.number)
                        end
                    end
                    local isRed = true
                    if (msg.type == ModelChat.MSGTYPE_NOTICE) then
                        --3是联盟互助 玩家主动援助他人，通过机制发送的私聊信息后，玩家自身不需要显示红点
                        if msg.playerId == meId then
                            isRed = false
                        end
                    end
                    if isRed then
                        if msg.channel ~= ModelChat.CHANNEL_PRIVATE then
                            self:SetChannelRed(msg.channel)
                        end
                        if msg.playerId ~= meId then
                            if msg.channel == ModelChat.CHANNEL_PRIVATE then
                                local atPlayerId = msg.playerId
                                if atPlayerId then
                                    self:SetPrivateChannelRed(atPlayerId)
                                end
                            end
                        end
                    end
                end

                if (msg.scrolling == 1 and gModelFunctionOpen:CheckIsOpened(10900001)) then
                    --跑马灯
                    table.insert(self._noticeInfoList, msg)
                end

                if msg.channel == ModelChat.CHANNEL_INVASION then
                    FireEvent(EventNames.ON_CHAT_MSG_UPDATE, msg)
                    printInfoN("EventNames.ON_CHAT_MSG_UPDATE")
                elseif msg.channel == ModelChat.CHANNEL_GUILD then
                    FireEvent(EventNames.ON_CHAT_MSG_GULID_UPDATE, msg)
                end
            end
            if (msg.channel == ModelChat.CHANNEL_PRIVATE) then
                self:AddPushPrivateChat(msg)
                --elseif msg.channel == ModelChat.CHANNEL_INVASION then
                --    FireEvent(EventNames.ON_CHAT_MSG_UPDATE,msg)
            elseif self._barrageChannel[msg.channel] then
                FireEvent(EventNames.ON_CHAT_WORLD_MSG, msg)
            end
        end
        if msg.channel == ModelChat.CHANNEL_PRIVATE then
            if msg.atPlayerId ~= meId then
                saveChatIdList[msg.atPlayerId] = true
            elseif msg.playerId ~= meId then
                saveChatIdList[msg.playerId] = true
            end
            isSaveChat = true
        end
    end
    if endMsg then
        local channel = endMsg.channel
        local sendTime = endMsg.sendTime
        chatChannelTime[channel] = sendTime
        local newChatChannelTime = ""
        local list = {}
        for i, v in pairs(chatChannelTime) do
            table.insert(list, string.format("%s=%s", i, v))
            --local old = newChatChannelTime
            --if old ~= "" then
            --    old = old .."|"
            --end
            --newChatChannelTime = old ..(i.."="..v)
        end
        newChatChannelTime = table.concat(list, "|")
        LPlayerPrefs.SetChatChannelTime(newChatChannelTime)
    end

    local closeTime = LPlayerPrefs.SetAnnCloseTime()
    local isShow = false
    if closeTime then
        closeTime = tonumber(closeTime)
        local interval = GameTable.GameMailConfigRef.noticesInterval * 60 or 0
        isShow = GetTimestamp() - closeTime >= interval
    else
        isShow = true
    end
    if isShow and self._noticeInfoList and #self._noticeInfoList > 0 and not GF.FindFirstWndByName("UISistemNotice") then
        if not gModelGeneral:IsInStory() and
                (self:GetChatSetValue(18) or not self._chatSetMap or self._chatSetMap[18] == nil) then
            GF.OpenUIGue("UISistemNotice")
        end
    end
    if isSaveChat then
        if (self._bRead) then
            self:GetChatSaveFile(saveChatIdList)
        end
    end
end
