function ModelChat:SetChatChannelCD(channel)
    --设置聊天频道CD计时
    local time = self:GetChannelCD(channel)
    self._channelListCD[channel] = time
    local key = tostring(channel)
    self._timer:TimerCreate(key, function(...)
        self:OnCountDown(...)
    end, 1, true, 1)
end
function ModelChat:OnCountDown(key)
    --冷却计时
    self._timer:TimerRemoveByKey(key)
    local cd = self._channelListCD[tonumber(key)]
    cd = cd - 1
    self._channelListCD[tonumber(key)] = cd
    if (cd > 0) then
        self._timer:TimerCreate(key, function(...)
            self:OnCountDown(...)
        end, 1, true, 1)
    end
end
