    local isMes = chatMsg.channel ~= ModelChat.CHANNEL_SYSTEM and chatMsg.playerId == gModelPlayer:GetPlayerId()--设置聊天是否自己
    chatMsg.isMe = isMes
    if isMes and (not chatMsg.level or chatMsg.level == 0) then
        chatMsg.level = gModelPlayer:GetPlayerLv()
    end

    local number = self._channleNmuber[chatMsg.channel]
    if (not number) then
        number = 0
    end
    number = number + 1
    self._channleNmuber[chatMsg.channel] = number
    chatMsg.number = number
    return chatMsg
end

