function ModelChat:AddPushPrivateChat(msg)
    --接收私聊消息时添加私聊
    local bPrivateChat = false
    local list = self:GetChatFriend()
    for i, v in pairs(list) do
        if (v.type ~= 0) then
            if (v.playerInfo.playerId ~= msg.atPlayerId and v.playerInfo.playerId ~= msg.playerId) then
                bPrivateChat = false
            end
        end
    end
    if (not bPrivateChat) then
        local playerId = msg.atPlayerId
        local name = msg.atPlayerName
        if (playerId == gModelPlayer:GetPlayerId()) then
            playerId = msg.playerId
            name = msg.playerName
        end
        local playerInfo = {}
        if msg.type == ModelChat.MSGTYPE_NOTICE then
            playerInfo = {
                playerId = playerId,
                name = name,
                serverId = msg.serverId,
                icon = msg.atHead,
                headFrame = msg.atHeadFrame,
                time = msg.sendTime,
            }
        else
            playerInfo = {
                playerId = playerId,
                name = name,
                serverId = msg.serverId,
                icon = msg.head,
                headFrame = msg.headFrame,
                time = msg.sendTime,
            }
        end
        self:AddPrivateChat(playerInfo, true)
        FireEvent(EventNames.ON_CHAT_FRIND_NEW, { playerInfo = playerInfo })
    end
end
function ModelChat:AddPrivateChat(playerInfo, bAdd)
    --添加私聊，bAdd--是否可无限添加
    local list = self:GetChatFriend()
    if (not playerInfo) then
        return list

    end
    --local list=self._privateChat
    local bTypeNil = false
    local lime = self:GetChatConfigRefByKey("SL_StoreNum")
    local idList = {}
    for i, v in pairs(list) do
        local info = v.playerInfo
        if (info) then
            idList[v.playerInfo.playerId] = v.playerInfo.playerId
        else
            bTypeNil = true
        end
    end

    if (#list == lime and bTypeNil and playerInfo and not idList[playerInfo.playerId]) then
        --到上限有空就删除
        for i, v in pairs(list) do
            if (v.type and v.type == 0) then
                table.remove(list, i)
                break
            end
        end
    end

    if (#list >= lime and playerInfo and not idList[playerInfo.playerId]) then
        --在加一层筛选  如果满了 并且加入的不在里面 就进行旧的移除
        local removeIndex = 0
        for i, v in pairs(list) do

            if removeIndex == 0 then
                removeIndex = 1
            end

            if checknumber(list[removeIndex].time) > checknumber(v.time) then
                --时间戳越小代表是旧的进行移除标记
                removeIndex = i
            end
        end
        if removeIndex > 0 then
            table.remove(list, removeIndex)
        end
    end

    if ((#list < lime or bTypeNil) or bAdd) then
        --能加就加
        for i = 1, #list do
            local data = list[i]
            if (data.playerInfo and data.playerInfo.playerId == playerInfo.playerId) then
                if playerInfo.time then
                    data.time = playerInfo.time
                end
                return list
            end
        end
        local addList = {
            type = 1,
            playerInfo = playerInfo,
            playerId = playerInfo.playerId
        }
        table.insert(list, addList)
        self._privateChat = list
    else
        --私聊会自动移除 不在进行提示11119
        --GF.ShowMessage(string.replace(ccClientText(11119), lime))
    end
    table.sort(list, function(a, b)
        if a.type ~= b.type then
            return a.type > b.type
        end
        if a.playerInfo and b.playerInfo then
            return a.playerInfo.playerId < b.playerInfo.playerId
        end
        return false
    end)
    return list
end
function ModelChat:DeletePrivateChat(playerInfo)
    local list = self._privateChat
    for i, v in pairs(list) do
        if (v.playerInfo and v.playerInfo.playerId == playerInfo.playerId) then
            self:DeleteChatFile(playerInfo.playerId)
            self:DeletePrivateChatInfo(playerInfo.playerId)
            table.remove(list, i)
            break
        end
    end
    self._privateChat = list
end
