function ModelChat:GetChatChannelIsOpent(channelId, index, bool, tipsTextRefId)
    --获取频道功能是否开启,index:1开放，2发言,3标签,bool是否弹提示
    local ref = self:GetChatChannelRefByChannelId(channelId)
    if not ref then
        return
    end
    local openId
    if (index == 1) then
        openId = ref.openId
    elseif (index == 3) then
        openId = ref.openIdGather
        if not openId or openId == "" then
            openId = ref.openId
        end
    elseif (index == 2) then
        if (not self:IsSendCD(channelId, bool, tipsTextRefId)) then
            return false
        end
        openId = ref.sendKey
    end
    local bOpent = self:CheckIsOpenedStr(openId, bool)
    if bOpent and ref.channelType == 3 and index == 2 then
        local childOpened = self:GetChildChannelIsOpened(channelId)
        if childOpened then
            return true
        end
        if (bool) then
            GF.ShowMessage(ccClientText(11155))
        end
        return false
    end
    if (channelId == ModelChat.CHANNEL_PROVINCE and bOpent) then
        local isProvince = gModelPlayer:GetProvince() > 0
        local isCity = true
        if not gLGameLanguage:IsKoreaRegion() then
            isCity = gModelPlayer:GetCity() > 0
        end

        if (isProvince and isCity) then
            return true
        end
        if (bool) then
            local refId, func
            local selfPlayerId = gModelPlayer:GetPlayerId()
            if not isProvince then
                GF.OpenWndUp("UISaySetPop")
                return false
            elseif not (gLGameLanguage:IsKoreaRegion() or isCity) then
                GF.OpenWndUp("UISaySetPop")
                return false
            end
            if func then
                GF.OpenWnd("UIOrdinTip", { refId = refId, func = func })
            end
        end
        return false
    end
    return bOpent
end

function ModelChat:GetChildChannelIsOpened(channel)
    local info = self:GetChildChannelOpenList(channel)
    if info then
        local openTIme = tonumber(info.openTIme) / 1000
        local endTIme = tonumber(info.endTIme) / 1000
        if openTIme == 0 or endTIme == 0 then
            return true
        end
        local currTime = GetTimestamp()
        if openTIme <= currTime and currTime <= endTIme then
            return true
        end
    end
    return false
end

function ModelChat:SetTranslate(itemdata)
    if itemdata.isMe then
        return
    end
    if itemdata.type ~= ModelChat.MSGTYPE_NORMAL and itemdata.type ~= ModelChat.MSGTYPE_AT then
        return
    end
    if self:GetTranslate(itemdata.channel, itemdata.number) then
        return
    end
    gLGameTranslator:GetTranslate(itemdata.msg, function(code, text)
        local channel = itemdata.channel
        local index = itemdata.number
        
        if index == nil then
            printInfoN2("ModelChat","index == nil--return  ")
            return 
        end 
        
        local _translateDateList = self._translateDateList or {}
        local list = _translateDateList[channel] or {}
        list[index] = text
        _translateDateList[channel] = list
        self._translateDateList = _translateDateList
        FireEvent(EventNames.ON_CHAT_TRANSLATE_CALL, code, index)
    end)
end
function ModelChat:GetTranslate(channel, index)
    local _translateDateList = self._translateDateList or {}
    local list = _translateDateList[channel] or {}
    local text = list[index]
    return text
end
function ModelChat:DelTranslate(itemdata)
    local channel = itemdata.channel
    local index = itemdata.number
    local _translateDateList = self._translateDateList or {}
    local list = _translateDateList[channel] or {}
    list[index] = nil
    _translateDateList[channel] = list
    self._translateDateList = _translateDateList
    FireEvent(EventNames.ON_CHAT_TRANSLATE_CALL, "", index)
end
function ModelChat:DelAllTranslate()
    self._translateDateList = {}
end

