function ModelChat:GetChatFriend()
    --获取私聊好友
    local list = self:GetPrivateChatList()
    local lime = self:GetChatConfigRefByKey("SL_StoreNum")
    if (#list < lime) then
        local bNil = false
        for i, v in pairs(list) do
            if (v.type and v.type == 0) then
                bNil = true
                break
            end
        end
        if (not bNil) then
            local addList = {
                type = 0
            }
            table.insert(list, addList)
        end
    end
    table.sort(list, function(a, b)
        if a.type ~= b.type then
            return a.type > b.type
        end
        if a.playerInfo and b.playerInfo then
            return a.playerInfo.playerId < b.playerInfo.playerId
        end
        return false
    end)
    return list
end
function ModelChat:GetNewInfoCount(list)
