function ModelChat:GetChannelInfoByChannel(channel)
    local _chatInfoList = self._chatInfoList or {}
    local chatChannels = _chatInfoList[channel] or {}
    local clearChatPlayerIdMap = self:GetClearChatPlayerMap()
    local myPlayerId = gModelPlayer:GetPlayerId()
    local list = {}
    for i,v in ipairs(chatChannels) do
        --- 清屏操作：清屏后该玩家的聊天消息对其他玩家不可见，自己可见
        if myPlayerId == v.playerId or not clearChatPlayerIdMap[v.playerId] then
            table.insert(list,v)
        end
    end
    return list
end
function ModelChat:GetChannleMsgByChannel(channel)
    local msgList = self:GetChannelInfoByChannel(channel)
    local list = {}
    for i, v in ipairs(msgList) do
        table.insert(list, v)
    end
    table.sort(list, function(a, b)
        local sendTimeA = a.sendTime
        local sendTimeB = b.sendTime
        if sendTimeA and sendTimeB and sendTimeA ~= sendTimeB then
            return sendTimeA > sendTimeB
        end
        return false
    end)
    return list
end
function ModelChat:SetChannelInfoByChannel(channel, msg)
    local list = self:GetChannelInfoByChannel(channel)
    table.insert(list, msg)
    if channel == ModelChat.CHANNEL_PRIVATE then
        table.sort(list, function(a, b)
            local sendTimeA = a.sendTime
            local sendTimeB = b.sendTime
            if sendTimeA and sendTimeB and sendTimeA ~= sendTimeB then
                return sendTimeA < sendTimeB
            end
            return false
        end)
    end
    self:SetChannelInfoByList(channel, list)
end
