function ModelChat:GetAirChannelList()
    local isAir, airList = self:GetIsAirList()
    local refList = self:GetChatChannelRef()
    local list = {}
    for i, v in pairs(refList) do
        if v.floatedGet ~= "" then
            if not isAir then
                local floatedGet = string.split(v.floatedGet, "=")
                if #floatedGet >= 2 then
                    if floatedGet[1] == "1" and floatedGet[2] == "1" then
                        table.insert(list, v)
                    end
                end
            elseif airList[v.channelId] then
                table.insert(list, v)
            end
        end
    end
    table.sort(list, function(a, b)
        return a.sort < b.sort
    end)
    return list
end
function ModelChat:GetAirChannelSetList()
    local isAir, airList = self:GetIsAirList()
    local refList = self:GetChatChannelRef()
    local list = {}
    for i, v in pairs(refList) do
        if v.floatedGet ~= "" then
            if not isAir then
                local floatedGet = string.split(v.floatedGet, "=")
                if #floatedGet >= 2 then
                    if floatedGet[1] == "1" then
                        local bool = floatedGet[2] == "1"
                        local data = {
                            ref = v,
                            bool = bool
                        }
                        table.insert(list, data)
                    end
                end
            else
                local bool = airList[v.channelId]
                local data = {
                    ref = v,
                    bool = bool
                }
                table.insert(list, data)
            end
        end
    end
    table.sort(list, function(a, b)
        return a.ref.sort < b.ref.sort
    end)
    return list
end
