function ModelChat:GetChildChannelListByChannel(channel)
    local list = {}
    local refList = self:GetChatChannelRef()
    for i, v in pairs(refList) do
        local sortSmall = v.sortSmall
        if sortSmall == channel then
            local isOpend = self:CheckIsOpenedStr(v.openId)
            if isOpend then
                table.insert(list, v)
            end
        end
    end
    table.sort(list, function(a, b)
        local aisOpened = (self:GetChildChannelIsOpened(a.channelId) or a.channelType == 1) and 1 or 2
        local bisOpened = (self:GetChildChannelIsOpened(b.channelId) or b.channelType == 1) and 1 or 2
        if aisOpened ~= bisOpened then
            return aisOpened < bisOpened
        end
        return a.sort < b.sort
    end)
    return list
end
function ModelChat:CheckIsOpenedStr(openId, isTips)
    local openIdArr = string.split(openId, "|")
    for j, k in ipairs(openIdArr) do
        local isOpend = gModelFunctionOpen:CheckIsOpened(tonumber(k))
        if isOpend then
            return true
        end
    end
    if isTips and openIdArr[1] then
        gModelFunctionOpen:CheckIsOpened(tonumber(openIdArr[1]), isTips)
    end
    return false
end
