ModelChat.ChatDirPath = CS.AppPersistentDataPath() .. "localchatcache/"--私聊保存路径
function ModelChat:GetChatSaveToFile()
    --初始化私聊
    if (self._bRead) then
        return
    end
    self._bRead = true
    self._chatFilePathList = {}
    local _privateChat = self._privateChat or {}
    local chatDirPath = ModelChat.ChatDirPath .. gModelPlayer:GetPlayerId() .. "/"
    ---WEBGL 不保存私聊
    local chatFileList
    if not CS.IsWebGL() then
        chatFileList = CS.DirectoryTopFileList(chatDirPath, true)
    end
    if (chatFileList and chatFileList.Length > 0) then
        for i = 0, chatFileList.Length - 1 do
            local playerIdFile = chatFileList[i]
            local pathText = string.match(playerIdFile, "%d+.txt")
            if (pathText) then
                local playerId = string.match(pathText, "%d+")
                local str = CS.FileReadText(playerIdFile)
                local strArr = string.split(str, "%%")
                local playerArr = string.split(strArr[1], "/")
                local list = JSON.decode(strArr[2])
                if list then
                    for i, v in ipairs(list) do
                        local chatMsg = StructChatMsg:New()
                        chatMsg:CreateByPb(v, true)
                        local isMes = chatMsg.playerId == gModelPlayer:GetPlayerId()
                        chatMsg.isMe = isMes
                        self:SetChannelInfoByChannel(ModelChat.CHANNEL_PRIVATE, chatMsg)
                    end
                    local isNew = false
                    for i, v in ipairs(_privateChat) do
                        if v.playerId and v.playerId == playerArr[2] then
                            isNew = true
                            break
                        end
                    end
                    if not isNew then
                        local playerInfo = {
                            playerId = playerArr[2],
                            name = playerArr[3],
                            serverId = tonumber(playerArr[4]),
                            icon = tonumber(playerArr[5]),
                            headFrame = tonumber(playerArr[6]),
                        }
                        local data = {
                            playerInfo = playerInfo,
                            playerId = playerId,
                            time = playerArr[1],
                            type = 1,
                        }
                        table.insert(_privateChat, data)
                    end
                end
            end
        end
    end
    self._privateChat = _privateChat
    self:GetChatSaveFile()
end
function ModelChat:GetPrivateChatList()
    --获取离线私聊列表
    return self._privateChat or {}
end
function ModelChat:SetPrivateSaveMsg(num)
    --获取需要保存的聊天
    local _privateChat = self._privateChat
    if (not _privateChat) then
        return {}
    end
    local list = {}
    for j, v in pairs(_privateChat) do
        if (v.type ~= 0) then
            local playerInfo = v.playerInfo
            local infoList = self:GetTypeInfo(ModelChat.CHANNEL_PRIVATE, v.playerInfo)
            --if (#infoList <= 0) then
            --    return
            --end
            local time = infoList[#infoList].sendTime or v.time
            local data = {
                type = v.type,
                playerInfo = playerInfo,
                time = time,
                infoList = infoList,
            }
            table.insert(list, data)
        end
    end
    local len = #list
    if (len > 0) then
        if (len > num) then
            table.sort(list, function(a, b)
                if (not a or not b) then
                    return false
                end
                return a.time > b.time
            end)
            local de = num + 1
            for i = de, len do
                self:DeletePrivateChat(list[i].playerInfo)--删除多余的聊天
            end
        end
    end
    return list
end
function ModelChat:GetChatSaveFile(saveChatIdList)
    local lime = self:GetPrivateChatInfoLime(ModelChat.CHANNEL_PRIVATE)
    local num = self:GetChatConfigRefByKey("SL_StoreNum")
    local list = self:SetPrivateSaveMsg(num)
    if (not list) then
        return
    end
    if CS.IsWebGL() then
        ---WebGL 不保存私聊
        return
    end
    for j, v in pairs(list) do
        if (v.type ~= 0) then
            local playerInfo = v.playerInfo
            if not saveChatIdList or saveChatIdList[playerInfo.playerId] then
                local time = v.time or 0
                local strF = string.format("%s/%s/%s/%s/%s/%s",
                        time, playerInfo.playerId, playerInfo.name, playerInfo.serverId, playerInfo.icon, playerInfo.headFrame)
                local infoList = v.infoList
                local len = #infoList
                if len > 0 then
                    local msgList = {}
                    if len > lime then
                        local start = len - (lime - 1)
                        for i = start, len do
                            table.insert(msgList, infoList[i])
                        end
                    else
                        msgList = infoList
                    end
                    local jsonStr = JSON.encode(msgList)
                    if not string.isempty(jsonStr) then
                        self:GetChatWriteFile(playerInfo.playerId, strF .. "%%" .. jsonStr)
                    end
                end
            end
        end
    end
end
function ModelChat:SetSaveInfo(info, i)
    local sendTime = info.sendTime
    if not sendTime or sendTime == "nil" then
        sendTime = GetTimestamp()
    end
    sendTime = tonumber(sendTime) + i
    local strF = string.format("%s/%s/%s/%s/%s/%s/%s/%s/%s",
            info.playerId, info.playerName, info.atPlayerId, info.atPlayerName, info.head, info.headFrame, info.serverId, info.msg, sendTime)
    return strF
end
function ModelChat:GetChatWriteFile(key, msg)
    if CS.IsWebGL() then
        --WEBGL 不保存私聊
        return
    end

    local chatDirPath = ModelChat.ChatDirPath .. gModelPlayer:GetPlayerId() .. "/"
    local _chatFilePath = chatDirPath .. key .. ".txt"
