function ModelChat:SetBarrageSav(channel, bool)
    --设置弹幕保存      true显示 去掉，false屏蔽 加上
    local barrageChannel = LPlayerPrefs.barrageChannel or ""
    local value = ""
    local index = 1
    local channelArr = string.split(barrageChannel, "=")
    if (bool) then
        if (not channelArr or #channelArr < 1) then
            return
        end
        for i, v in ipairs(channelArr) do
            if (tostring(channel) ~= v) then
                if (index > 1) then
                    value = value .. "=" .. v
                else
                    value = v
                end
                index = index + 1
            end
        end
    else
        if (#channelArr > 0) then
            value = barrageChannel .. "=" .. channel
        else
            value = tostring(channel)
        end
    end
    LPlayerPrefs.SetBarrageChannel(value)
end
function ModelChat:GetBarrageIsShow(channel)
    --是否显示弹幕
    local ref = self:GetChatChannelRefByChannelId(channel)
    if not ref then
        return false
    end
    local open = self:CheckIsOpenedStr(ref.openId)
    if not open then
        return false
    end
    local barrageChannel = LPlayerPrefs.barrageChannel
    if (not barrageChannel or barrageChannel == "") then
        return true
    end
    local channelArr = string.split(barrageChannel, "=")
    if (not channelArr or #channelArr < 1) then
        return true
    end
    for i, v in ipairs(channelArr) do
        if (channel == tonumber(v)) then
            return false
        end
    end
    return true
end
