function ModelChat:SetChatSkipFun(textTran, InstanceID, itemdata, msg, _uiHyperList, wndName, isTarget)
    --设置跳转超链接
    local id = itemdata.atPlayerId
    if itemdata.type == ModelChat.MSGTYPE_NOTICE then
        local arr = string.split(msg, "=")
        id = arr[1]
        msg = arr[2]
    end
    local noticeRefId = tonumber(id)
    local ref = gModelChat:GetMailNoticesRefByRefId(noticeRefId)
    if (not ref) then
        return msg
    end
    local text = ccLngText(ref.content)
    if (string.isempty(text)) then
        return msg
    end
    local jumpList = {}
    if (ref.jump ~= "") then
        jumpList = string.split(ref.jump, ";")
    end
    local kList = {}
    local k = "<a (key%d+)>"
    for v in string.gmatch(text, k) do
        table.insert(kList, v)
    end
    local mList = {}
    local m = "<a key%d+>([^%<]*)"
    for v in string.gmatch(text, m) do
        local listStr = self:ShiftESC(v)
        table.insert(mList, listStr)
    end
    local len = #kList
    local uiHyper
    if (len > 0) then
        uiHyper = _uiHyperList[InstanceID]
        if not uiHyper then
            uiHyper = UIHyperText:New()
            _uiHyperList[InstanceID] = uiHyper
        end
        uiHyper:Create(textTran, isTarget)
    end
    local keyList = {}
    for i = 1, len do
        local key = kList[i]
        local txt = mList[i]
        local value = ""
        local index = keyList[key]
        if (not index) then
            index = 1
        else
            index = index + 1
        end
        keyList[key] = index
        local t = "<a " .. key .. ">" .. txt .. "</a>"
        if (key == "key2") then
            value = jumpList[index]
        else
            local pattern = JSON.decode(msg)
            if (not pattern) then
                return msg
            end
            for k, v in pairs(pattern) do
                if (k == key) then
                    local arry = string.split(v, ";")
                    value = arry[index]
                end
            end
        end
        local mText = uiHyper:AddHyper(txt, { func = function(data)
            self:ClickHyper(data, wndName, itemdata)
        end, para = { key = key, msg = value } })
        text = string.gsub(text, t, mText)
    end
    text = LUtil.GetReplacedContent(text, msg, nil, noticeRefId)
    return text
end

function ModelChat:ShiftESC(str)
    --对正则表达式中，特殊符号加转义字符，否则无法识别
    local shiftList = {
        ['%['] = "%%[",
        ['%]'] = "%%]",
    }

    for k, v in pairs(shiftList) do
        str = string.gsub(str, k, v)
    end
    return str
end

function ModelChat:ClickHyper(data, wndName, itemdata)
    local key = data.key
    local v = data.msg
    if (key == ModelChat.HYPER_PLAYERINIFPOP) then
        gModelGeneral:PlayerShowReq(v, LCombatTypeConst.COMBAT_MAIN, LPlayerShowConst.OTHER_SYSTEM)
    elseif (key == ModelChat.HYPER_JUMP) then
        local refId = tonumber(v)
        if (not gModelFunctionOpen:CheckIsOpened(refId, true)) then
            return
        end
        GF.CloseWndByName("UISayPop")
        gModelFunctionOpen:Jump(refId, wndName)
    elseif (key == ModelChat.HYPER_APPLYFORGUILD) then
        --这里加一个判断 是否开启公会
        local isopen, msg = gModelFunctionOpen:CheckIsOpened(12100000, true)
        if isopen then
            gModelGuild:OnJoinGuildReq(1, v)
        end
    elseif key == ModelChat.HYPER_WEB_LINK then
        local url = tostring(v)
        CS.UApplication.OpenURL(url)
    elseif key == ModelChat.HYPER_OPENITEMWND then
        gModelGeneral:OpenItemInfoTip(tonumber(v))
    elseif key == ModelChat.HYPER_KEY_4 then
        local url = tostring(v)
        CS.UApplication.OpenURL(url)
    elseif key == ModelChat.HYPER_KEY_6 then
        local playerId = itemdata.playerId
        gModelGuild:OnGuildHelpThankReq(playerId, tonumber(v))
    elseif key == ModelChat.HYPER_KEY_7 then
        local heroRefId = tonumber(v)
        GF.OpenWndTop("UINewSagaStarPre", { refId = heroRefId })
    elseif key == ModelChat.HYPER_KEY_8 then
        gModelGuild:OnGuildMemberListReq(v, itemdata.serverId)
    elseif key == ModelChat.HYPER_KEY_9 then
        local para = itemdata.msg
        local pattern = JSON.decode(para)
        if (not pattern) then
            return
        end
        local a2 = pattern.a2
        local arr = string.split(a2, "|")
        local rankRefId = tonumber(arr[1])
        local ref = gModelRank:GetRankingRefData(rankRefId)

        --CheckIsOpened
        local openid = ref.functionId

        local isOpen = true

        if openid > 0 then
            isOpen = gModelFunctionOpen:CheckIsOpened(openid, true)
        end

        if not isOpen then
            return
        end

        if not ref then
            return
        end
        GF.OpenWndBottom("UIRkPop", { refId = rankRefId, page = 2 })
    elseif key == ModelChat.HYPER_KEY_10 then
        local para = itemdata.msg
        local pattern = JSON.decode(para)
        if (not pattern) then
            return
        end
        local refId = pattern.a2
        GF.OpenWnd("UIKuafuWarAuto", { refId = refId })
    end
end
function ModelChat:SetShareType(itemdata, msg)
    if (itemdata.type ~= ModelChat.MSGTYPE_SHARE or not itemdata.shareData) then
        return false, msg
    end
    local _shareData = itemdata.shareData
    local _shareMsg = self:GetShareConfigRef(itemdata.shareType)
    if _shareData == "" or _shareData.shareData == "" or _shareMsg == "" then
        return false, " "
    end
    local info = {}
    local _shareInfo = _shareData.shareData

    local data = JSON.decode(_shareInfo)
    if data then
        _shareInfo = data
    end

    local func = self._getShareDataFunc[itemdata.shareType]
    if func then
        local _data, _msg = func(itemdata)
        if _data then
            _shareInfo = _data
        end
        if _msg then
            _shareMsg = _msg
        end
    end

    info.msg = _shareMsg
    info.item = _shareInfo
    info.item.shareType = itemdata.shareType
    info.item.playerName = itemdata.playerName
    return true, info
end
function ModelChat:OnAddHyper(textTran, InstanceID, data, _uiHyperList, func, isTarget)
    --设置分享超链接
    if (not data.item) then
        return data.msg
    end
    local uiHyper = _uiHyperList[InstanceID]
    if not uiHyper then
        uiHyper = UIHyperText:New()
        _uiHyperList[InstanceID] = uiHyper
    end
    uiHyper:Create(textTran, isTarget)
    local msg = data.msg
    local name, color = self:GetAddHyperShareNameColor(data)
    if name == "" then
        return " "
    end
    LxUiHelper.SetNormalTextClick(textTran, function()
        if func then
            func()
        end
    end)
    name = uiHyper:AddHyper(name, { func = function(...)
        self:OpenTipWnd(...)
    end, para = data })
    local colorName = LUtil.FormatColorStr(name, color)

    printInfoN2("--", "---")
    if data.item.shareType == ModelChat.CHAT_SHARE_43 then
        msg = string.replace(msg, data.item[1], colorName)
    elseif data.item.shareType == ModelChat.CHATSHARE_27  then 
        msg = msg .. " #a1#"
        msg = string.replace(msg, colorName)
    else
        msg = string.replace(msg, colorName)
    end

    printInfoN2("--", "---")
    return msg
end
function ModelChat:GetAddHyperShareNameColor(data)
    local item = data.item
    local _shareType = item.shareType
    local func = self._getShareNameFunc[_shareType]
    local name, color
    if func then
        name, color = func(data)
    end
    return name or "", color
end
function ModelChat:OpenTipWnd(data)
    --分享超链接 点击方法
    local item = data.item
    local _shareType = item.shareType
    local func = self._onClickShareFunc[_shareType]
    if func then
        func(data)
    end
end
