        local combatName
        if type(tonumber(combatType)) == "number" then
            local combatTypeIndex = tonumber(combatType)
            local ref = GameTable.BattleGameRef[combatTypeIndex]
            if not ref then
                printInfoNR2("配置缺失", string.format("GameTable.BattleGameRef[%s]", combatTypeIndex or "nil"))
                return ccClientText(17015)
            end
            combatName = ccLngText(ref.name)
        else
            combatName = combatType
        end
        name = string.replace(ccClientText(23406), combatName)
    else
        name = ccClientText(17015)
    end
    return name
end
