function ModelChat:GetReportUrl(serverId, reportId)
    local reportUrl
    if serverId == gLGameLogin:GetActualServerId() then
        reportUrl = gLGameLogin:GetHttpReportUrl()
    else
        reportUrl = gModelBattle:GetReportUrlByServerId(serverId)
    end
    local root = string.split(reportId, "-") or {}
    root = root[1] or "inst"
    local url = string.format("%s%s/%s/%s.json", reportUrl, serverId, root, reportId)
    return url
end

