--清理工作
--停止计时器之类的
function ModelChat:OnModelClear()
    local timer = self._timer
    if timer then
        timer:Destroy()
        self._timer = nil
    end
end

function ModelChat:InitChatSetData()
    local chatSetMap = self._chatSetMap
    if chatSetMap then
        return
    end
    chatSetMap = {}
    self._chatSetMap = chatSetMap

    if not string.isempty(LPlayerPrefs.chatSetServerList) then
        local strs = string.split(LPlayerPrefs.chatSetServerList, "|")
        for k, v in ipairs(strs) do
            local temps = string.split(v, "=")
            local key = tonumber(temps[1])
            local value = tonumber(temps[2]) == 1
            chatSetMap[key] = value
        end
    end
end

function ModelChat:GetChatSetValue(type)
    self:InitChatSetData()

    return self._chatSetMap[type] or false
end

function ModelChat:SetChatSetValue(type, value)
    local oldValue = self:GetChatSetValue(type)
    if oldValue == value then
        return
    end
    self._chatSetMap[type] = value
    self:SaveChatSetPara()

    if type == 17 then
        FireEvent(EventNames.ON_CHAT_CHANGE_VIEW_SET)
    elseif type == 18 then
        --删除所有广播记录
        gModelChat:DelAllNoticeInfo()
    elseif type == 7 then
        FireEvent(EventNames.ON_CHAT_CHANGE_CHATAIRPOP_SET)
    end
end

function ModelChat:SaveChatSetPara()
    if not self._chatSetMap then
        return
    end
    local dataList = {}
    for k, v in pairs(self._chatSetMap) do
        local str = string.format("%s=%s", k, v and 1 or 0)
        table.insert(dataList, str)
    end

    local record = table.concat(dataList, '|')
    LPlayerPrefs.SetChatSetServerList(record)
end

function ModelChat:InsertionSendTimeToChatInfo(channel, chagInfo)
    if not gLGameLanguage:IsJapanRegion() then
        return chagInfo
    end

    if channel ~= ModelChat.CHANNEL_PRIVATE then
        return chagInfo
    end

    local curTime = GetTimestamp()
    local chatTimeStamp = gModelChat:GetChatConfigRefByKey("chatTimeStamp") or 600

    local resultList = {}
    local timeTemplate
    local lastSendTime
    for k, v in ipairs(chagInfo) do
        local sendTime = tonumber(v.sendTime) / 1000
        if not lastSendTime then
            timeTemplate = curTime - sendTime
        else
            timeTemplate = sendTime - lastSendTime
        end

        if timeTemplate > chatTimeStamp then
            local timeStr = LUtil.FormatChatTime(sendTime)
            table.insert(resultList, {
                isTime = true,
                timeStr = timeStr,
            })
        end
        table.insert(resultList, v)
        lastSendTime = sendTime
    end

    return resultList
end

function ModelChat:OnClearChatMsgResp(pb)
    local type = pb.type
    local clearChatPlayerIdMap = self._clearChatPlayerIdMap
    if not clearChatPlayerIdMap then
        clearChatPlayerIdMap = {}
        self._clearChatPlayerIdMap = clearChatPlayerIdMap
    end

    local playerId = pb.playerId or {}
    for i,v in ipairs(playerId) do
        clearChatPlayerIdMap[v] = true
    end
end

function ModelChat:GetClearChatPlayerMap()
    return self._clearChatPlayerIdMap or {}
end

